    32→
    33→import java.util.Collections;
    34→import java.util.HashMap;
    35→import java.util.Iterator;
    36→import java.util.Map;
    37→import java.util.stream.Collectors;
    38→
    39→import static org.apache.kafka.common.requests.ProduceResponse.INVALID_OFFSET;
    40→
    41→public class ProduceRequest extends AbstractRequest {
    42→
    43→    public static final short LAST_STABLE_VERSION_BEFORE_TRANSACTION_V2 = 11;
    44→
    45→    public static Builder builder(ProduceRequestData data, boolean useTransactionV1Version) {
    46→        // When we use transaction V1 protocol in transaction we set the request version upper limit to
    47→        // LAST_STABLE_VERSION_BEFORE_TRANSACTION_V2 so that the broker knows that we're using transaction protocol V1.
    48→        short maxVersion = useTransactionV1Version ?
    49→            LAST_STABLE_VERSION_BEFORE_TRANSACTION_V2 : ApiKeys.PRODUCE.latestVersion();
    50→        return new Builder(ApiKeys.PRODUCE.oldestVersion(), maxVersion, data);
    51→    }
    52→
    53→    public static Builder builder(ProduceRequestData data) {
    54→        return builder(data, false);
    55→    }
    56→
    57→    public static class Builder extends AbstractRequest.Builder<ProduceRequest> {
    58→        private final ProduceRequestData data;
    59→
    60→        public Builder(short minVersion,
    61→                       short maxVersion,
    62→                       ProduceRequestData data) {
    63→            super(ApiKeys.PRODUCE, minVersion, maxVersion);
    64→            this.data = data;
    65→        }
    66→
    67→        @Override
    68→        public ProduceRequest build(short version) {
    69→            // Validate the given records first
    70→            data.topicData().forEach(tpd ->
    71→                tpd.partitionData().forEach(partitionProduceData ->
    72→                    ProduceRequest.validateRecords(version, partitionProduceData.records())));
    73→            return new ProduceRequest(data, version);
    74→        }
    75→
    76→        @Override
    77→        public String toString() {
    78→            return "(type=ProduceRequest" +
    79→                    ", acks=" + data.acks() +
    80→                    ", timeout=" + data.timeoutMs() +
    81→                    ", partitionRecords=(" + data.topicData().stream().flatMap(d -> d.partitionData().stream()).collect(Collectors.toList()) +
    82→                    "), transactionalId='" + (data.transactionalId() != null ? data.transactionalId() : "") +
    83→                    "'";
    84→        }
    85→    }
    86→
    87→    /**
    88→     * We have to copy acks, timeout, transactionalId and partitionSizes from data since data maybe reset to eliminate
    89→     * the reference to ByteBuffer but those metadata are still useful.
    90→     */
    91→    private final short acks;
    92→    private final int timeout;
    93→    private final String transactionalId;
    94→    // This is set to null by `clearPartitionRecords` to prevent unnecessary memory retention when a produce request is
    95→    // put in the purgatory (due to client throttling, it can take a while before the response is sent).
    96→    // Care should be taken in methods that use this field.
    97→    private volatile ProduceRequestData data;
    98→    // the partitionSizes is lazily initialized since it is used by server-side in production.
    99→    private volatile Map<TopicIdPartition, Integer> partitionSizes;
   100→
   101→    public ProduceRequest(ProduceRequestData produceRequestData, short version) {
   102→        super(ApiKeys.PRODUCE, version);
   103→        this.data = produceRequestData;
   104→        this.acks = data.acks();
   105→        this.timeout = data.timeoutMs();
   106→        this.transactionalId = data.transactionalId();
   107→    }
   108→
   109→    // visible for testing
   110→    Map<TopicIdPartition, Integer> partitionSizes() {
   111→        if (partitionSizes == null) {
   112→            // this method may be called by different thread (see the comment on data)
   113→            synchronized (this) {
   114→                if (partitionSizes == null) {
   115→                    Map<TopicIdPartition, Integer> tmpPartitionSizes = new HashMap<>();
   116→                    data.topicData().forEach(topicData ->
   117→                        topicData.partitionData().forEach(partitionData ->
   118→                            // While topic id and name might not be populated at the same time in the request all the time;
   119→                            // for example on server side they will never be populated together while in produce client they will be,
   120→                            // to simplify initializing `TopicIdPartition` the code will use both topic name and id.
   121→                            // TopicId will be Uuid.ZERO_UUID in versions < 13 and topic name will be used as main identifier of topic partition.
   122→                            // TopicName will be empty string in versions >= 13 and topic id will be used as the main identifier.
   123→                            tmpPartitionSizes.compute(new TopicIdPartition(topicData.topicId(), partitionData.index(), topicData.name()),
   124→                                (ignored, previousValue) ->
   125→                                    partitionData.records().sizeInBytes() + (previousValue == null ? 0 : previousValue))
   126→                        )
   127→                    );
   128→                    partitionSizes = tmpPartitionSizes;
   129→                }
   130→            }
   131→        }
   132→        return partitionSizes;
   133→    }
   134→
   135→    /**
   136→     * @return data or IllegalStateException if the data is removed (to prevent unnecessary memory retention).
   137→     */
   138→    @Override
   139→    public ProduceRequestData data() {
   140→        // Store it in a local variable to protect against concurrent updates
   141→        ProduceRequestData tmp = data;
   142→        if (tmp == null)
   143→            throw new IllegalStateException("The partition records are no longer available because clearPartitionRecords() has been invoked.");
   144→        return tmp;
   145→    }
   146→
   147→    @Override
   148→    public String toString(boolean verbose) {
   149→        // Use the same format as `Struct.toString()`
   150→        StringBuilder bld = new StringBuilder();
   151→        bld.append("{acks=").append(acks)
   152→                .append(",timeout=").append(timeout);
   153→
   154→        if (verbose)
   155→            bld.append(",partitionSizes=").append(Utils.mkString(partitionSizes(), "[", "]", "=", ","));
   156→        else
   157→            bld.append(",numPartitions=").append(partitionSizes().size());
   158→
   159→        bld.append("}");
   160→        return bld.toString();
   161→    }
   162→
   163→    @Override
   164→    public ProduceResponse getErrorResponse(int throttleTimeMs, Throwable e) {
   165→        /* In case the producer doesn't actually want any response */
   166→        if (acks == 0) return null;
   167→        ApiError apiError = ApiError.fromThrowable(e);
   168→        ProduceResponseData data = new ProduceResponseData().setThrottleTimeMs(throttleTimeMs);
   169→        partitionSizes().forEach((tpId, ignored) -> {
   170→            ProduceResponseData.TopicProduceResponse tpr = data.responses().find(tpId.topic(), tpId.topicId());
   171→            if (tpr == null) {
   172→                tpr = new ProduceResponseData.TopicProduceResponse().setName(tpId.topic()).setTopicId(tpId.topicId());
   173→                data.responses().add(tpr);
   174→            }
   175→            tpr.partitionResponses().add(new ProduceResponseData.PartitionProduceResponse()
   176→                    .setIndex(tpId.partition())
   177→                    .setRecordErrors(Collections.emptyList())
   178→                    .setBaseOffset(INVALID_OFFSET)
   179→                    .setLogAppendTimeMs(RecordBatch.NO_TIMESTAMP)
   180→                    .setLogStartOffset(INVALID_OFFSET)
   181→                    .setErrorMessage(apiError.message())
   182→                    .setErrorCode(apiError.error().code()));
   183→        });
   184→        return new ProduceResponse(data);
   185→    }
   186→
   187→    @Override
   188→    public Map<Errors, Integer> errorCounts(Throwable e) {
   189→        Errors error = Errors.forException(e);
   190→        return Collections.singletonMap(error, partitionSizes().size());
   191→    }
   192→
   193→    public short acks() {
   194→        return acks;
   195→    }
   196→
   197→    public int timeout() {
   198→        return timeout;
   199→    }
   200→
   201→    public String transactionalId() {
   202→        return transactionalId;
   203→    }
   204→
   205→    public void clearPartitionRecords() {
   206→        // lazily initialize partitionSizes.
   207→        partitionSizes();
   208→        data = null;
   209→    }
   210→
   211→    public static void validateRecords(short version, BaseRecords baseRecords) {
   212→        if (baseRecords instanceof Records) {
   213→            Records records = (Records) baseRecords;
   214→            Iterator<? extends RecordBatch> iterator = records.batches().iterator();
   215→            if (!iterator.hasNext())
   216→                throw new InvalidRecordException("Produce requests with version " + version + " must have at least " +
   217→                        "one record batch per partition");
   218→
   219→            RecordBatch entry = iterator.next();
   220→            if (entry.magic() != RecordBatch.MAGIC_VALUE_V2)
   221→                throw new InvalidRecordException("Produce requests with version " + version + " are only allowed to " +
   222→                        "contain record batches with magic version 2");
   223→            if (version < 7 && entry.compressionType() == CompressionType.ZSTD) {
   224→                throw new UnsupportedCompressionTypeException("Produce requests with version " + version + " are not allowed to " +
   225→                        "use ZStandard compression");
   226→            }
   227→
   228→            if (iterator.hasNext())
   229→                throw new InvalidRecordException("Produce requests with version " + version + " are only allowed to " +
   230→                        "contain exactly one record batch per partition");
   231→        }
   232→    }
   233→
   234→    public static ProduceRequest parse(Readable readable, short version) {
   235→        return new ProduceRequest(new ProduceRequestData(readable, version), version);
   236→    }
   237→
   238→    public static boolean isTransactionV2Requested(short version) {
   239→        return version > LAST_STABLE_VERSION_BEFORE_TRANSACTION_V2;
   240→    }
   241→
   242→}
